{"command":["bash","-lc","python - <<'PY'
import os
root='src'
entries=[]
for dirpath,_,filenames in os.walk(root):
    for f in filenames:
        if f.endswith(('.ts','.tsx', '.mts', '.cts')):
            path=os.path.join(dirpath,f)
            with open(path,'rb') as fh:
                count=sum(1 for _ in fh)
            entries.append((count,path))
entries.sort(reverse=True)
for count,path in entries[:20]:
    print(count,path)
PY"],"workdir":"/Users/duhl/git/anedot-frontend","timeout_ms":100000}

